class MemoizedComponent:
  def __init__(self, array):
    self.array = array
    self.rendered = None

  def render(self):
    if self.rendered is None or self.array != self.rendered['array']:
      self.rendered = {'array': ' '.join(self.array)}
    return self.rendered['array']
